import { Markup } from '@/checkout/components';
import { TermsAndConditions as TermsAndConditionsComponent } from '@/checkout/components/TermsAndConditions';
import { AgreementMode } from '@/checkout/data/models';
import { getLatestCheckoutUpdate, state } from '@/checkout/lib';
import { Checkbox } from '@adobe-commerce/elsie/components';
import { MarkupText, useText } from '@adobe-commerce/elsie/i18n';
import {
  Container,
  Slot,
  SlotMethod,
  SlotProps,
} from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { useEffect, useState } from 'preact/hooks';

export interface TermsAndConditionsProps {
  active?: boolean;
  slots?: {
    Agreements?: SlotProps<{
      appendAgreement: SlotMethod<{
        name: string;
        mode: AgreementMode;
        translationId?: string;
        text?: string;
      }>;
    }>;
  };
}

export const TermsAndConditions: Container<TermsAndConditionsProps> = ({
  active = true,
  slots,
  ...props
}) => {
  const [isInitialized, setIsInitialized] = useState(false);
  const [error, setError] = useState<string>('');

  const { errorMessage } = useText({
    errorMessage: 'Checkout.TermsAndConditions.error',
  });

  const disabledViaConfig = state.config?.agreementsEnabled === false;

  const handleChange = () => {
    setError('');
  };

  const handleInvalid = () => {
    setError(errorMessage);
  };

  useEffect(() => {
    if (!active || disabledViaConfig) return;

    const pastUpdate = getLatestCheckoutUpdate();

    if (pastUpdate) {
      setIsInitialized(true);
      return;
    }

    const onCheckoutInit = events.on(
      'checkout/initialized',
      () => {
        setIsInitialized(true);
      },
      { eager: true }
    );
    return () => {
      onCheckoutInit?.off();
    };
  }, [active, disabledViaConfig]);

  return (
    <TermsAndConditionsComponent
      {...props}
      agreements={
        <Slot
          context={{
            appendAgreement(callback) {
              this._registerMethod((...attrs) => {
                const _agreement = callback(...attrs);

                if (!_agreement) return;

                const { mode, name, text, translationId } = _agreement;

                if (!text && !translationId) {
                  console.warn(
                    `The agreement ${name} is misconfigured. Please provide a text or a translationId.`
                  );
                  return;
                }

                const label = text ? (
                  <Markup html={text} />
                ) : (
                  <MarkupText id={translationId!} />
                );

                const agreement = (
                  <Checkbox
                    checked={mode === AgreementMode.AUTO}
                    label={label}
                    name={name}
                    required={true}
                    onChange={handleChange}
                    onInvalid={handleInvalid}
                  />
                );

                this._setProps((prev: any) => ({
                  children: [...(prev.children || []), agreement],
                }));
              });
            },
          }}
          name="Agreements"
          slot={slots?.Agreements}
        />
      }
      error={error}
      initialized={isInitialized}
      visible={active && !disabledViaConfig}
    />
  );
};
